Add-Type -AssemblyName System.Windows.Forms;$RCLONE=(Get-Command rclone -EA SilentlyContinue).Source;$BUCKET="r2-mauto:m-auto-software";$SCAN_DIR="S:\Delphi";$R2_PREFIX="Delphi";$REPO_DIR="D:\Tutorials\m-auto.online";$JSON_OUT="$REPO_DIR\delphi_links.json";$EXPIRES="2h";$e=[char]27;if(-not(Test-Path $RCLONE)){[System.Windows.Forms.MessageBox]::Show("rclone nao encontrado","Renew - Erro",[System.Windows.Forms.MessageBoxButtons]::OK,[System.Windows.Forms.MessageBoxIcon]::Error)|Out-Null;exit 1};if(-not(Test-Path $SCAN_DIR)){[System.Windows.Forms.MessageBox]::Show("Pasta nao encontrada: $SCAN_DIR","Renew - Erro",[System.Windows.Forms.MessageBoxButtons]::OK,[System.Windows.Forms.MessageBoxIcon]::Error)|Out-Null;exit 1};$allFiles=Get-ChildItem $SCAN_DIR -Recurse -File -EA SilentlyContinue|Sort-Object FullName;$Host.UI.RawUI.WindowTitle="M-Auto - Renew Delphi Links";Clear-Host;Write-Host "  ${e}[38;2;155;89;182m+--+${e}[0m";Write-Host "  ${e}[38;2;155;89;182m|${e}[0m  M-Auto Renew Delphi";Write-Host "  ${e}[38;2;155;89;182m+--+${e}[0m";Write-Host "  Ficheiros: $($allFiles.Count)";Write-Host "  >> Processando...";$files=foreach($f in $allFiles){$rP=$f.FullName.Substring($SCAN_DIR.Length).TrimStart('\').Replace('\','/');[PSCustomObject]@{label=$f.Name;dest=$rP;r2="$R2_PREFIX/$rP"}};$pool=[System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspacePool(1,[Math]::Min($files.Count,8));$pool.Open();$jobs=foreach($f in $files){$ps=[System.Management.Automation.PowerShell]::Create();$ps.RunspacePool=$pool;[void]$ps.AddScript({param($rc,$bkt,$r2p,$exp);$url=&$rc link "$bkt/$r2p" --expire $exp 2>&1;@{ok=($LASTEXITCODE-eq0);url="$url".Trim()}}).AddParameters(@{rc=$RCLONE;bkt=$BUCKET;r2p=$f.r2;exp=$EXPIRES});@{ps=$ps;h=$ps.BeginInvoke();f=$f}};$exp_dt=(Get-Date).AddHours(2).ToUniversalTime().ToString("o");$lst=[System.Collections.Generic.List[object]]::new();$err=0;foreach($j in $jobs){$o=$j.ps.EndInvoke($j.h);$j.ps.Dispose();if($o.ok){Write-Host "[✓] $($j.f.label)";$lst.Add([PSCustomObject]@{name=$j.f.dest;url=$o.url})}else{Write-Host "[✗] $($j.f.label)";$err++}};$pool.Close();Write-Host ">> Finalizando...";$jObj=[PSCustomObject]@{expires=$exp_dt;files=$lst.ToArray()};$utf8=[System.Text.UTF8Encoding]::new($false);[System.IO.File]::WriteAllText($JSON_OUT,($jObj|ConvertTo-Json -Depth 3 -Compress),$utf8);Write-Host "[OK] JSON guardado ($($lst.Count) ficheiros)";Push-Location $REPO_DIR;git add delphi_links.json 2>&1|Out-Null;git commit -m "renew: delphi_links.json $(Get-Date -Format 'yyyy-MM-dd HH:mm') ($($lst.Count))" 2>&1|Out-Null;git push 2>&1|Out-Null;Write-Host "[OK] Publicado";Pop-Location;Write-Host "[OK] $($lst.Count) links gerados.";Read-Host "ENTER para sair"
